diff --git a/packages/components/containers/contacts/group/ContactGroupDetailsModal.test.tsx b/packages/components/containers/contacts/group/ContactGroupDetailsModal.test.tsx
--- a/packages/components/containers/contacts/group/ContactGroupDetailsModal.test.tsx
+++ b/packages/components/containers/contacts/group/ContactGroupDetailsModal.test.tsx
@@ -1,5 +1,6 @@
 import { LABEL_TYPE } from '@proton/shared/lib/constants';
 import { ContactEmail, ContactGroup } from '@proton/shared/lib/interfaces/contacts';
+import { fireEvent } from '@testing-library/react';
 import { STATUS } from '@proton/shared/lib/models/cache';

 import { cache, clearAll, minimalCache, render } from '../tests/render';
@@ -63,9 +64,69 @@ describe('ContactGroupDetailsModal', () => {
         const { getByText } = render(<ContactGroupDetailsModal open={true} {...props} />, false);

         getByText(group.Name);
-        getByText('3 members');
+        getByText('3 email addresses');
         getByText(contactEmail1.Name);
         getByText(contactEmail2.Name);
         getByText(contactEmail3.Name);
     });
+
+    it('should limit compose recipients to maximum allowed count', () => {
+        const manyEmails = Array.from({ length: 30 }, (_, i) => ({
+            ID: `ce-${i}`,
+            Email: `user${i}@test.com`,
+            Name: `User ${i}`,
+            LabelIDs: ['ContactGroupID'],
+            ContactID: `contact-${i}`,
+            Type: [],
+            Defaults: 0,
+            Order: i,
+            LastUsedTime: 0,
+        }));
+
+        minimalCache();
+        cache.set('Labels', { status: STATUS.RESOLVED, value: [group] });
+        cache.set('ContactEmails', { status: STATUS.RESOLVED, value: manyEmails });
+
+        const onCompose = jest.fn();
+        const { getByTestId } = render(
+            <ContactGroupDetailsModal open={true} {...props} onCompose={onCompose} />,
+            false
+        );
+        fireEvent.click(getByTestId('group-summary:compose'));
+        expect(onCompose).toHaveBeenCalled();
+        const [recipients] = onCompose.mock.calls[0];
+        expect(recipients).toHaveLength(25);
+    });
+
+    it('should display contacts in simplified mode with copy actions', () => {
+        minimalCache();
+        cache.set('Labels', { status: STATUS.RESOLVED, value: [group] });
+        cache.set('ContactEmails', { status: STATUS.RESOLVED, value: [contactEmail1, contactEmail2, contactEmail3] });
+
+        const onCompose = jest.fn();
+        const { getAllByTestId } = render(
+            <ContactGroupDetailsModal open={true} {...props} onCompose={onCompose} />,
+            false
+        );
+        const contactNames = getAllByTestId('recipient:dropdown-item--contact-name');
+        expect(contactNames).toHaveLength(3);
+        const copyButtons = getAllByTestId('recipient:dropdown-item--copy-address-button');
+        expect(copyButtons).toHaveLength(3);
+    });
+
+    it('should keep modal open after compose action', () => {
+        minimalCache();
+        cache.set('Labels', { status: STATUS.RESOLVED, value: [group] });
+        cache.set('ContactEmails', { status: STATUS.RESOLVED, value: [contactEmail1, contactEmail2, contactEmail3] });
+
+        const onCompose = jest.fn();
+        const onClose = jest.fn();
+        const { getByTestId } = render(
+            <ContactGroupDetailsModal open={true} {...props} onCompose={onCompose} onClose={onClose} />,
+            false
+        );
+        fireEvent.click(getByTestId('group-summary:compose'));
+        expect(onCompose).toHaveBeenCalled();
+        expect(onClose).not.toHaveBeenCalled();
+    });
 });
